INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-3218f787-moex-00266', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '有關社會學對教育的描述，下列何者正確？', '["衝突論者認為，人力可以是一種資本，教育算是一種對人力素質的投資", "人力資本論者認為教育是階級宰制的工具", "學校生活中的同儕互動、師生相處、教室和學校儀式等，可以稱為隱性課程（hiddencurriculum）", "衝突論者認為教育是培育或挑選人才的配置過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00267', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '關於社會學的三大傳統，下列敘述何者正確？', '["馬克思（KarlMarx）認為社會存在於個人之外，對個人有其約制性", "韋伯（MaxWeber）主要著作是對於資本主義社會剝削的批評", "涂爾幹（EmileDurkheim）的自殺論強調以社會事實研究社會現象", "馬克思（KarlMarx）的社會學也可稱為詮釋（interpretive）社會學"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00268', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '對於家庭生產和資源分配的敘述，下列何者正確？', '["家庭內代間資源移轉和外部社會制度沒有關係", "家庭中可移轉至下一代的資源只有財產一種", "家庭資源的代間移轉，類型只有親代對子代的經濟支援", "資源交換論者認為，由於妻子在經濟上仰賴丈夫，故投入家事勞務來換取經濟資源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00269', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列對馬克思（KarlMarx）提出異化（alienation）的說明，何者正確？', '["異化是指和自己本性一致", "異化被用來解釋說明資本主義的勞動特徵", "工人和資本家的關係是以集體利益做考量", "工人可在製造過程充分展現自身的技藝"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00270', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '關於「任務中心」社會工作模式的陳述，下列何者正確？', '["將遭遇問題的個人視為是功能不彰或生病的病人，社會工作者主要是代替案主解決問題使其恢 復功能", "社工的處遇介入需要針對問題訂定可行的目標，培養案主解決問題的能力", "由於案主通常為弱勢及資源缺乏的民眾，社會工作者的處遇策略重點是主動替案主連結資源", "社會工作者的主要角色在為案主分析問題，為其申請政府資源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00271', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列何者不是社會工作基本的倫理原則？', '["立基於人的尊嚴及價值，對案主應保持非評斷及接納的態度", "為避免案主與社會工作者間發生情感轉移的現象，工作者應隨時保持中立的立場，與個案保持 專業上的切割", "案主自決指的是，個案有權力及需求，能在不被強迫或操縱下自由地做決定", "社會工作者透過對案主的接納，產生與案主內在自我的連結，不僅肯定了人性，同時也帶給案 主轉化的力量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00272', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列對於各種「社區工作模式」的說明，何者正確？', '["社會計畫模式是指社區面對壓迫、不公、不義之事，由專家協助動員社區民眾以爭取社區權益", "行為改變模式是指社區中經常有一些不合時宜的風俗習慣，藉由處罰及獎勵措施來改變行為， 促進社區發展", "社區行動模式是當社區民眾遇到共同的健康、交通、福利等共同問題，透過專業人士制定行動 計畫解決問題", "地方發展模式是透過民主的程序形成社區共識，並擴大社區民眾參與，共同解決社區問題，促 成社區改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00273', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於「老人社會工作」相關概念的說明，何者正確？', '["進行個案的老化評估時，社會工作者主要使用「生物醫學」此單一模式來評估", "老人的整合評估用於社會工作服務處遇介入前，整合評估包括身體功能、心理認知功能及社會 家庭支持功能", "長期照顧服務的提供，只需要考慮被照顧者的需求", "長期照顧服務主要可區分為社區式照顧及機構式照顧兩種服務方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00274', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於婦女社會工作之內涵與原則，何者正確？', '["Hanmer 及 Statham（1989）曾提出婦女社會工作的七項原則，但其中不包括為女性主義實務 工作建構倫理守則", "現在社會文化環境對婦女不利的因素已越來越少，因此增加男性的權能也是婦女社會工作的重點", "反歧視與反壓迫也是婦女社會工作的重要視角，反壓迫主要在強調案主的自我反省，檢視自己 受壓迫的原因", "增加權能是現在社會中婦女社會工作的主要原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00275', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '關於社會工作者「替代性創傷」此概念的相關說明，下列何者正確？', '["社會工作者擁有助人專業知識，可以運用專業知識處理自己的問題，所以不會有替代性創傷的 問題", "替代性創傷是指社會工作者在處理案主問題時回想起自己過去相同的經驗，所產生舊傷復發的 狀況", "替代性創傷又稱為次級創傷，源於社會工作者處理案主創傷事件時的深度同理，所產生的情感 連結", "替代性創傷即為情感轉移，由於社會工作者在服務過程中使案主產生愛慕的情愫，所造成的創傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
